                # Resolve the full extraction path for this member
                member_path = os.path.realpath(os.path.join(dest_real, member.name))
                # Ensure the resolved path is inside the destination directory
                if not (member_path.startswith(dest_real + os.sep) or member_path == dest_real):
                    return False

                # For symlinks and hardlinks, validate the link target
                if member.issym() or member.islnk():
                    linkname = member.linkname
                    if os.path.isabs(linkname):
                        target_path = os.path.realpath(linkname)
                    else:
                        target_path = os.path.realpath(
