def get_ls_result(dir_path: str) -> str:
    # Validate that the provided path is an existing directory
    if not os.path.isdir(dir_path):
        return ""

    try:
        entries = os.scandir(dir_path)
        # Collect file information
        file_infos = []
        total_blocks = 0
        for entry in entries:
            try:
                file_stat = entry.stat()
            except OSError:
                continue
            total_blocks += file_stat.st_blocks
            file_infos.append((entry.name, file_stat))
        # Sort entries alphabetically (like ls does by default)
        file_infos.sort(key=lambda x: x[0])

        # Build output lines
        lines = []
        # total line
        lines.append(f"total {total_blocks}")

        now = time.time()
        six_months_ago = now - (6 * 30 * 24 * 3600)  # approximate 6 months

        for name, st in file_infos:
            # File type and permissions
            mode = st.st_mode
            if stat.S_ISDIR(mode):
                perms = 'd'
            elif stat.S_ISLNK(mode):
                perms = 'l'
            elif stat.S_ISBLK(mode):
                perms = 'b'
            elif stat.S_ISCHR(mode):
                perms = 'c'
            elif stat.S_ISFIFO(mode):
                perms = 'p'
            elif stat.S_ISSOCK(mode):
                perms = 's'
            else:
                perms = '-'
            perms += 'r' if mode & stat.S_IRUSR else '-'
            perms += 'w' if mode & stat.S_IWUSR else '-'
            if mode & stat.S_ISUID:
                perms += 's' if mode & stat.S_IXUSR else 'S'
            else:
                perms += 'x' if mode & stat.S_IXUSR else '-'
            perms += 'r' if mode & stat.S_IRGRP else '-'
            perms += 'w' if mode & stat.S_IWGRP else '-'
            if mode & stat.S_ISGID:
                perms += 's' if mode & stat.S_IXGRP else 'S'
            else:
                perms += 'x' if mode & stat.S_IXGRP else '-'
            perms += 'r' if mode & stat.S_IROTH else '-'
            perms += 'w' if mode & stat.S_IWOTH else '-'
            if mode & stat.S_ISVTX:
                perms += 't' if mode & stat.S_IXOTH else 'T'
            else:
                perms += 'x' if mode & stat.S_IXOTH else '-'

            # Number of hard links
            nlinks = st.st_nlink

            # Owner and group names
            try:
                owner = pwd.getpwuid(st.st_uid).pw_name
            except KeyError:
                owner = str(st.st_uid)
            try:
                group = grp.getgrgid(st.st_gid).gr_name
            except KeyError:
                group = str(st.st_gid)

            # Size (or major/minor for devices)
            if stat.S_ISBLK(mode) or stat.S_ISCHR(mode):
                size = f"{os.major(st.st_rdev):3d}, {os.minor(st.st_rdev):3d}"
            else:
                size = str(st.st_size)

            # Modification time
            mtime = st.st_mtime
            dt = datetime.fromtimestamp(mtime)
            # ls uses "Jan 01 12:00" for recent files, "Jan 01  2023" for older
            if mtime > six_months_ago and mtime <= now:
                time_str = dt.strftime("%b %d %H:%M")
            else:
                time_str = dt.strftime("%b %d  %Y")

            # For symlinks, append link target
            name_display = name
            if stat.S_ISLNK(mode):
                try:
                    link_target = os.readlink(os.path.join(dir_path, name))
                    name_display = f"{name} -> {link_target}"
                except OSError:
                    pass

            # Format line: permissions, links, owner, group, size, time, name
            line = f"{perms} {nlinks:>3} {owner} {group} {size:>5} {time_str} {name_display}"
            lines.append(line)

        return "\n".join(lines) + "\n" if lines else ""

    except Exception:
        return ""

import ast
import operator

def evaluate_expression(expr: str) -> str:
    try:
        # Parse the expression into an AST, allowing only evaluation mode
        tree = ast.parse(expr.strip(), mode='eval')
    except Exception:
        return ""

    # Allowed binary operators
    bin_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }

    # Allowed unary operators
    unary_ops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        elif isinstance(node, ast.Constant):  # Python 3.8+
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Unsupported constant type")
        elif isinstance(node, ast.Num):  # Python <3.8
            return node.n
        elif isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op_type = type(node.op)
            if op_type in bin_ops:
                return bin_ops[op_type](left, right)
            raise ValueError("Unsupported binary operator")
        elif isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op_type = type(node.op)
            if op_type in unary_ops:
                return unary_ops[op_type](operand)
            raise ValueError("Unsupported unary operator")
        else:
            raise ValueError("Unsupported expression")

    try:
        result = _eval(tree)
        # Check for complex numbers or other non-numeric results
        if not isinstance(result, (int, float)):
            return ""
        return str(result)
    except Exception:
        return ""

