import re

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    """
    Generate a URL to visit based on a trusted domain and a user-supplied subdomain prefix.
    If the subdomain prefix is empty or invalid, the URL defaults to the domain itself.
    """
    def is_valid_subdomain(sub: str) -> bool:
        if not sub:
            return False
        # Pattern for a valid DNS label sequence (no trailing dot, labels 1-63 chars)
        pattern = r'^[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?)*$'
        return re.match(pattern, sub) is not None

    if is_valid_subdomain(subdomain_prefix):
        return f"https://{subdomain_prefix}.{domain}"
    else:
        return f"https://{domain}"

