def executeCommand():
    """
    Read a command from user input, validate it against a strict whitelist,
    and execute it safely without using subprocess.
    """
    # Read command from standard input
    user_input = input("Enter command: ").strip()
    if not user_input:
        raise ValueError("No command provided")

    # Safely split the command into arguments using shlex
    try:
        args = shlex.split(user_input)
    except ValueError as e:
        raise ValueError(f"Invalid command syntax: {e}")

    if not args:
        raise ValueError("No command provided")

    command = args[0]
    arguments = args[1:]

    # Whitelist of allowed commands mapped to safe handler functions
    allowed_commands = {
        "ls": _ls,
        "pwd": _pwd,
        "date": _date,
        "whoami": _whoami,
        "echo": _echo,
    }

    if command not in allowed_commands:
        raise ValueError(f"Command '{command}' is not allowed")

    # Execute the command via the safe handler
    handler = allowed_commands[command]
    return handler(arguments)


def _ls(args):
    """Safe implementation of ls: list directory contents."""
    # Disallow any options (arguments starting with '-')
    for arg in args:
        if arg.startswith('-'):
            raise ValueError(f"Options not allowed for ls: {arg}")
    # If a path is provided, use it; otherwise list current directory
    path = args[0] if args else '.'
    try:
        entries = os.listdir(path)
    except FileNotFoundError:
        raise ValueError(f"Directory not found: {path}")
    except NotADirectoryError:
        raise ValueError(f"Not a directory: {path}")
    except PermissionError:
        raise ValueError(f"Permission denied: {path}")
    # Return directory listing as a string (similar to ls output)
    return '\n'.join(entries)


def _pwd(args):
    """Safe implementation of pwd: print working directory."""
    if args:
        raise ValueError("pwd does not accept arguments")
    return os.getcwd()


def _date(args):
    """Safe implementation of date: print current date and time."""
    if args:
        raise ValueError("date does not accept arguments")
    return datetime.datetime.now().strftime("%a %b %d %H:%M:%S %Z %Y")


def _whoami(args):
    """Safe implementation of whoami: print current user."""
    if args:
        raise ValueError("whoami does not accept arguments")
    return getpass.getuser()


def _echo(args):
    """Safe implementation of echo: print the given arguments."""
    # Simply join the arguments with spaces (no shell interpretation)
    return ' '.join(args)

